const items = $input.all();
const now = new Date();
const cutoff = 48 * 60 * 60 * 1000;
const cjkRegex = /[\u4e00-\u9fff\u3040-\u30ff\uac00-\ud7af]/;
const htmlRegex = /<[^>]*>/g;

// Process and filter the items
const processedItems = items.map(item => {
  const d = item.json;
  if (!d || Object.keys(d).length === 0) return null; // Catch completely empty items

  let rawDate = null;
  try {
    rawDate = d.isoDate || d.pubDate || d.published || d['dc:date'] || null;
  } catch (e) {}

  let summary = d['content:encodedSnippet'] || d.contentSnippet || d.summary || d.description || '';
  summary = summary.replace(htmlRegex, '').trim();
  if (summary.length < 30 || summary === 'Comments') summary = '';
  summary = summary.slice(0, 500);

  const author = d.creator || d['dc:creator'] || d.author || 'Unknown';
  const link = d.link || d.url || '';
  let source = 'unknown';
  if (link.includes('ycombinator')) source = 'hackernews';
  else if (link.includes('dev.to'))  source = 'devto';
  else if (link.includes('techcrunch')) source = 'techcrunch';
  else if (link.includes('reddit'))  source = 'reddit';

  let publishedISO = null;
  let age = 0;
  if (rawDate) {
      try {
          publishedISO = new Date(rawDate).toISOString();
          age = now - new Date(publishedISO);
      } catch (e) { } // Catch invalid dates
  }

  return {
    json: {
      title:     d.title || 'No title',
      url:       link,
      summary:   summary,
      author:    author,
      published: publishedISO,
      source:    source,
      age_hours: Math.round(age / (1000 * 60 * 60))
    }
  };
})
.filter(item => item && item.json.url && item.json.title !== 'No title')
.filter(item => !cjkRegex.test(item.json.title))
.filter(item => item.json.age_hours <= 48);

// THE FIX: If the array is empty (feeds failed or 0 fresh articles), 
// return a dummy item so n8n continues to the IF node.
if (processedItems.length === 0) {
  return [{
    json: {
      is_empty_fallback: true
    }
  }];
}

return processedItems;

const unseenUrls = $('Postgres — Dedup Check').all().map(i => i.json.url);
const allArticles = $('Has Fresh Articles?').all(0, 0);

const fresh = allArticles.filter(a => unseenUrls.includes(a.json.url));

const scored = fresh.map(item => {
  const a = item.json;
  let score = 0;

  if (a.summary && a.summary.length > 100) score += 3;
  if (a.source === 'techcrunch') score += 2;
  if (a.source === 'devto') score += 2;
  if (a.source === 'reddit') score += 1;
  if (a.age_hours <= 6) score += 3;
  else if (a.age_hours <= 12) score += 2;
  else if (a.age_hours <= 24) score += 1;

  const keywords = ['ai', 'llm', 'gpt', 'model', 'developer', 'code', 'api', 'open source', 'startup'];
  const titleLower = a.title.toLowerCase();
  keywords.forEach(k => { if (titleLower.includes(k)) score += 1; });
  score = Math.min(score, 10)
  return { json: { ...a, score } };
});

scored.sort((a, b) => b.json.score - a.json.score);
return scored;

