INSERT INTO content_pipeline (source_url, title, summary, source_name, status, score)
VALUES
{{ $input.all().map(i => 
  `('${i.json.url.replace(/'/g, "''")}', '${i.json.title.replace(/'/g, "''")}', '${(i.json.summary || '').replace(/'/g, "''")}', '${i.json.source}', 'candidate', ${i.json.score})`
).join(',\n') }}
ON CONFLICT (source_url) DO NOTHING;

